func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	assignCount := dispatch.AssignsLen

	// Try each order sequentially
	for orderIdx := 0; orderIdx < nOrders; orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		bestAssignIdx := -1
		bestDeltaCost := 1e308

		// Evaluate insertion into existing non‑empty assigns first (in original order)
		for idx := 0; idx < assignCount; idx++ {
			assign := &dispatch.Assigns[idx]

			// Skip empty slots beyond current AssignsLen? Already guarded by assignCount.
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			delta := newCost - oldCost
			if delta < bestDeltaCost {
				bestDeltaCost = delta
				bestAssignIdx = idx
			}
			// Undo trial
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		// Also evaluate starting a fresh assign at the next available slot if within bounds
		nextFreshIdx := assignCount
		if nextFreshIdx < MAXASSIGNS {
			freshAssign := &dispatch.Assigns[nextFreshIdx]
			// Remember original state (empty)
			oldEmptyCost := freshAssign.Cost
			ok := freshAssign.AddShip(shipID, ori, des)
			if ok {
				freshAssign.GenRoute()
				newCost := freshAssign.Cost
				if newCost >= 0 {
					delta := newCost - oldEmptyCost
					if delta < bestDeltaCost {
						bestDeltaCost = delta
						bestAssignIdx = nextFreshIdx
					}
				}
				// Undo trial
				freshAssign.RemoveShip(shipID)
				freshAssign.GenRoute()
			}
		}

		// Commit the best found insertion
		if bestAssignIdx >= 0 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
			// Expand AssignsLen if we used a fresh assign
			if bestAssignIdx == assignCount {
				assignCount++
				dispatch.AssignsLen = assignCount
			}
		} else {
			// Fallback: force insertion into a brand‑new assign even if cost negative,
			// because every order must be assigned. Use the first empty slot beyond current.
			fallbackIdx := assignCount
			if fallbackIdx < MAXASSIGNS {
				fbAssign := &dispatch.Assigns[fallbackIdx]
				_ = fbAssign.AddShip(shipID, ori, des)
				fbAssign.GenRoute()
				assignCount++
				dispatch.AssignsLen = assignCount
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

