func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	shipIdBase := total_ship
	for orderIdx := range oris {
		shipId := shipIdBase + orderIdx
		bestAssignIdx := -1
		bestScore := 1e100
		savedStates := make([]struct {
			cost     float64
			routeOK  bool
		}, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i].cost = dispatch.Assigns[i].Cost
			savedStates[i].routeOK = dispatch.Assigns[i].Cost >= 0
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			if !savedStates[i].routeOK {
				continue
			}
			savedCost := dispatch.Assigns[i].Cost
			if dispatch.Assigns[i].AddShip(shipId, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - savedCost
					timeTightness := 0.0
					if dispatch.Assigns[i].StationCurrent.TimeStart > 0 || dispatch.Assigns[i].StationCurrent.TimeEnd > 0 {
						twLength := float64(dess[orderIdx].TimeEnd - dess[orderIdx].TimeStart + 1)
						if twLength <= 0 {
