						}
						travelToDes := cal_dis(oris[orderIdx], dess[orderIdx])
						travelFromCur := cal_dis(dispatch.Assigns[i].StationCurrent, oris[orderIdx])
						estimatedArrival := travelFromCur + travelToDes*0.5
						tightnessRatio := estimatedArrival / twLength
						if tightnessRatio > 1 {
							timeTightness = tightnessRatio * 10
						} else {
							timeTightness = 1.0 / (tightnessRatio + 0.01)
						}
					}
					score := delta*(1.0+timeTightness*0.3) + float64(i)*0.001
					if score < bestScore {
						bestScore = score
						bestAssignIdx = i
					}
				}
				dispatch.Assigns[i].RemoveShip(shipId)
				dispatch.Assigns[i].GenRoute()
				dispatch.Assigns[i].Cost = savedCost
			}
		}
		if bestAssignIdx != -1 {
			dispatch.Assigns[bestAssignIdx].AddShip(shipId, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			continue
		}
