					dispatch.Assigns[i].GenRoute()
					dispatch.Assigns[i].Cost = savedEmptyCost
				}
			}
		}
		if !fallbackAssigned {
			idx := dispatch.AssignsLen
			if idx >= MAXASSIGNS {
				for j := 0; j < MAXASSIGNS; j++ {
					if dispatch.Assigns[j].Cost < 0 {
						idx = j
						break
					}
				}
				if idx >= MAXASSIGNS {
					idx = 0
				}
			}
			dispatch.Assigns[idx].RemoveShip(-1)
			dispatch.Assigns[idx].GenRoute()
			ok := dispatch.Assigns[idx].AddShip(shipId, oris[orderIdx], dess[orderIdx])
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 && idx == dispatch.AssignsLen {
